157→public fun ASTNode.parent(
158→    elementType: IElementType,
159→    strict: Boolean = true,
160→): ASTNode? {
161→    var n: ASTNode? = if (strict) this.treeParent else this
162→    while (n != null) {
163→        if (n.elementType == elementType) {
164→            return n
165→        }
166→        n = n.treeParent
167→    }
