/**
 * Disallows the usage of the old `ktlint-disable` and `ktlint-enable` directives. Those directives are to be replaced with
 * `@Suppress` annotations.
 *
 * The rule can not be suppressed via the `@Suppress` annotation or the old `ktlint-disable` directive as that would result in a chicken
 * and egg problem.
 */
public class KtlintSuppressionRule :
    StandardRule(
        id = "ktlint-suppression",
        visitorModifiers =
            setOf(
                VisitorModifier.RunAsLateAsPossible,
            ),
    ) {
    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        when (node.elementType) {
            EOL_COMMENT -> visitEolComment(node, autoCorrect, emit)
            BLOCK_COMMENT -> visitBlockComment(node, autoCorrect, emit)
        }
    }

    private fun visitEolComment(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        val commentText =
            node
                .text
                .removePrefix("//")
                .trim()
        val parts = commentText.split(" ").filter { it.isNotBlank() }
        if (parts.isEmpty() || parts[0] != KTLINT_DISABLE) {
            return
        }

        val suppressionIds = parts.drop(1).toSuppressAnnotationValues()
        emit(
            node.startOffset,
            "Directive 'ktlint-disable' in EOL comment is deprecated. Replace with @Suppress annotation",
            true,
        )
        if (autoCorrect) {
            replaceEolCommentDirectiveWithSuppressAnnotation(node, suppressionIds)
        }
    }

    private fun visitBlockComment(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        val commentText =
            node
                .text
                .removePrefix("/*")
                .removeSuffix("*/")
                .trim()
        val parts = commentText.split(" ").filter { it.isNotBlank() }
        if (parts.isEmpty()) {
            return
        }

        when (parts[0]) {
            KTLINT_DISABLE -> {
                val suppressionIds = parts.drop(1).toSuppressAnnotationValues()
                emit(
                    node.startOffset,
                    "Directive 'ktlint-disable' in block comment is deprecated. Replace with @Suppress annotation",
                    true,
                )
                if (autoCorrect) {
                    replaceBlockCommentDirectiveWithSuppressAnnotation(node, suppressionIds)
