        node.treeParent.removeChild(node)
    }

    private fun replaceBlockCommentDirectiveWithSuppressAnnotation(
        node: ASTNode,
        suppressionIds: List<String>,
    ) {
        // Find and remove the matching enable comment first (before we lose track of it)
        val enableComment = findMatchingEnableComment(node, suppressionIds)
        if (enableComment != null) {
            removeNodeAndSurroundingWhitespace(enableComment)
        }

