        if (enableComment != null) {
            removeNodeAndSurroundingWhitespace(enableComment)
        }

        // Find the target to annotate - it's the next code sibling after the disable comment
        val target = findTargetForBlockComment(node)
        if (target != null) {
            addSuppressAnnotation(target, suppressionIds)
        }

        // Remove the disable comment
        removeNodeAndSurroundingWhitespace(node)
    }

    /**
     * Find the target node for an EOL comment. The target is the closest parent that is a declaration or expression and
     * that is a direct child of the file, script, class body, or block (i.e., it is a "statement-level" node).
     */
    private fun findTargetForEolComment(node: ASTNode): ASTNode? {
        var current = node.treeParent
        while (current != null) {
            if (current.elementType == FILE) {
                return null
            }
            val psi = current.psi
            if (psi is KtDeclaration || psi is KtExpression) {
                return current
            }
            current = current.treeParent
        }
        return null
    }

    private fun findTargetForBlockComment(node: ASTNode): ASTNode? {
        val nextSibling = node.nextCodeSibling()
        if (nextSibling != null) {
            val psi = nextSibling.psi
            if (psi is KtDeclaration || psi is KtExpression) {
                return nextSibling
            }
        }
        return null
    }

    private fun findMatchingEnableComment(
        disableNode: ASTNode,
        suppressionIds: List<String>,
    ): ASTNode? {
        var sibling = disableNode.treeNext
        while (sibling != null) {
            if (sibling.elementType == BLOCK_COMMENT) {
                val text =
                    sibling
                        .text
                        .removePrefix("/*")
                        .removeSuffix("*/")
                        .trim()
                val parts = text.split(" ").filter { it.isNotBlank() }
                if (parts.isNotEmpty() && parts[0] == KTLINT_ENABLE) {
                    val enableRuleIds = parts.drop(1).toSuppressAnnotationValues()
                    if (enableRuleIds == suppressionIds) {
                        return sibling
                    }
                }
            }
            sibling = sibling.treeNext
        }
        return null
    }

    private fun removeNodeAndSurroundingWhitespace(node: ASTNode) {
        val prevLeaf = node.prevLeaf()
        val nextLeaf = node.nextLeaf()

        val parent = node.treeParent
        parent.removeChild(node)

        // Clean up whitespace
        if (prevLeaf != null && prevLeaf.elementType == WHITE_SPACE && prevLeaf.textContains('\n') &&
            nextLeaf != null && nextLeaf.elementType == WHITE_SPACE && nextLeaf.textContains('\n')
        ) {
            try {
                nextLeaf.treeParent?.removeChild(nextLeaf)
            } catch (_: Exception) {
                // Node may have already been removed
            }
        } else if (prevLeaf != null && prevLeaf.elementType == WHITE_SPACE && !prevLeaf.textContains('\n')) {
            try {
                prevLeaf.treeParent?.removeChild(prevLeaf)
            } catch (_: Exception) {
                // Node may have already been removed
            }
        }
    }

    private fun addSuppressAnnotation(
        target: ASTNode,
        suppressionIds: List<String>,
    ) {
        val psiElement = target.psi
        if (psiElement is KtAnnotated) {
            val existingSuppress = findExistingSuppressAnnotation(psiElement)
            if (existingSuppress != null) {
                mergeWithExistingSuppress(existingSuppress, suppressionIds)
                return
            }
        }

        val indent = target.indent(includeNewline = false)
        val annotationText = "@Suppress(${suppressionIds.joinToString(", ") { "\"$it\"" }})"

        // Insert the @Suppress annotation before the target, on a new line with proper indent
        val prevWhitespace = target.prevLeaf()
        if (prevWhitespace != null && prevWhitespace.elementType == WHITE_SPACE && prevWhitespace.textContains('\n')) {
            val newText = prevWhitespace.text + "$annotationText\n$indent"
            (prevWhitespace as LeafPsiElement).rawReplaceWithText(newText)
        } else {
            // No preceding whitespace with newline - we're likely at the start of the file
            val firstLeaf = target.firstChildNode ?: target
            if (firstLeaf is LeafPsiElement) {
                PsiWhiteSpaceImpl("$annotationText\n$indent").also { ws ->
                    firstLeaf.rawInsertBeforeMe(ws)
                }
            }
        }
    }

    private fun findExistingSuppressAnnotation(ktAnnotated: KtAnnotated): KtAnnotationEntry? =
        ktAnnotated
            .annotationEntries
            .firstOrNull { annotationEntry ->
                annotationEntry
                    .calleeExpression
                    ?.constructorReferenceExpression
                    ?.getReferencedName() in SUPPRESS_ANNOTATIONS
            }

    private fun mergeWithExistingSuppress(
        existingSuppress: KtAnnotationEntry,
        newSuppressionIds: List<String>,
    ) {
        val existingValues =
            existingSuppress
                .valueArguments
                .mapNotNull { it.getArgumentExpression()?.text }

        // Combine existing and new values, avoid duplicates
        val quotedNewValues = newSuppressionIds.map { "\"$it\"" }
        val allValues = (existingValues + quotedNewValues).distinct()

        val newAnnotationText = "@Suppress(${allValues.joinToString(", ")})"

        // Replace the entire annotation text by replacing the text in the node
        val node = existingSuppress.node
        val parent = node.treeParent
        if (parent != null) {
            val firstChild = node.firstChildNode
            val lastChild = node.lastChildNode
            if (firstChild is LeafPsiElement && firstChild === lastChild) {
                firstChild.rawReplaceWithText(newAnnotationText)
            }
        }
    }

    private companion object {
        val SUPPRESS_ANNOTATIONS = setOf("Suppress", "SuppressWarnings")
        const val KTLINT_DISABLE = "ktlint-disable"
        const val KTLINT_ENABLE = "ktlint-enable"
    }
}

public val KTLINT_SUPPRESSION_RULE_ID: RuleId = KtlintSuppressionRule().ruleId
