 12→/**
 13→ * Sorts the [RuleProvider]s based on [Rule.VisitorModifier]s.
 14→ */
 15→internal class RuleProviderSorter {
 16→    /**
 17→     * Prevent duplicate debug logging whenever the same set of [Rule.id]s (but not the same instance) are sorted. As
 18→     * the sorting of the [RuleProvider] has to be executed for each file.
 19→     */
 20→    private val debugLogCache = mutableMapOf<Int, Boolean>()
 21→
 22→    @Synchronized
 23→    fun getSortedRuleProviders(ruleProviders: Set<RuleProvider>): List<RuleProvider> =
 24→        ruleProviders
 25→            .sort()
 26→            .also { sortedRuleProviders ->
 27→                if (LOGGER.isDebugEnabled) {
 28→                    logSortedRuleProviders(sortedRuleProviders)
 29→                }
 30→            }
 31→
 32→    private fun logSortedRuleProviders(sortedRuleProviders: List<RuleProvider>) {
 33→        debugLogCache
 34→            .putIfAbsent(createHashCode(sortedRuleProviders), true)
 35→            .also { previousValue ->
 36→                if (previousValue == null) {
 37→                    // Logging was not printed for this combination of rule providers as no entry was found in the cache
 38→                    sortedRuleProviders
 39→                        .joinToString(prefix = "Rules will be executed in order below:") {
 40→                            "\n           - ${it.ruleId.value}"
 41→                        }.also { LOGGER.debug(it) }
 42→                }
 43→            }
 44→    }
 45→
 46→    private fun createHashCode(sortedRuleProviders: List<RuleProvider>): Int =
 47→        sortedRuleProviders
 48→            .joinToString(
 49→                prefix = "rule-ids=[",
 50→                separator = ",",
 51→                postfix = "]",
 52→            ) { it.ruleId.value }
 53→            .hashCode()
 54→
 55→    private fun Set<RuleProvider>.sort(): List<RuleProvider> {
 56→        forEach { ruleProvider ->
 57→            ruleProvider.hasNoVisitorModifierReferringToSelf()
 58→        }
 59→
 60→        val ruleIdsToBeSorted = map { it.ruleId }.toSet()
 61→        val unprocessedRuleProviders =
 62→            sortedWith(defaultRuleExecutionOrderComparator())
 63→                .toMutableList()
 64→        val sortedRuleProviders = mutableListOf<RuleProvider>()
 65→        val ruleIdsSortedRuleProviders = mutableSetOf<RuleId>()
 66→
 67→        // Initially the list only contains the rules not depending on another rule.
 68→        unprocessedRuleProviders
 69→            .filter { !it.runAsLateAsPossible && it.hasNoRunAfterRules() }
 70→            .forEach { ruleProvider ->
 71→                sortedRuleProviders.add(ruleProvider)
 72→                ruleIdsSortedRuleProviders.add(ruleProvider.ruleId)
 73→            }
 74→        unprocessedRuleProviders.removeAll(sortedRuleProviders)
 75→        while (unprocessedRuleProviders.isNotEmpty()) {
 76→            val ruleProvider =
 77→                unprocessedRuleProviders
 78→                    .firstOrNull { ruleProvider ->
 79→                        ruleProvider
 80→                            .runAfterRules
 81→                            .filter { it.ruleId in ruleIdsToBeSorted }
 82→                            .all { it.ruleId in ruleIdsSortedRuleProviders }
 83→                    }
 84→                    ?: throw IllegalStateException(
 85→                        "Can not complete sorting of rule providers as next item can not be determined.",
 86→                    )
 87→            sortedRuleProviders.add(ruleProvider)
 88→            ruleIdsSortedRuleProviders.add(ruleProvider.ruleId)
 89→            unprocessedRuleProviders.remove(ruleProvider)
 90→        }
 91→        return sortedRuleProviders
 92→    }
