103→    private fun defaultRuleExecutionOrderComparator() =
104→        // The sort order below should guarantee a stable order of the rule between multiple invocations of KtLint given
105→        // the same set of input parameters. There should be no dependency on data ordering outside this class.
106→        compareBy<RuleProvider> {
107→            if (it.runAsLateAsPossible) {
108→                1
109→            } else {
110→                0
111→            }
112→        }.thenBy {
113→            if (it.ruleId.ruleSetId == RuleSetId.STANDARD) {
114→                0
115→            } else {
116→                1
117→            }
118→        }.thenBy { it.ruleId.value }
