/**
 * Disallows the usage of the old `ktlint-disable` and `ktlint-enable` directives. Those directives are to be replaced with
 * `@Suppress` annotations.
 *
 * The rule can not be suppressed via the `@Suppress` annotation or the old `ktlint-disable` directive as that would result in a chicken
 * and egg problem.
 */
public class KtlintSuppressionRule :
    StandardRule(
        id = "ktlint-suppression",
        visitorModifiers =
            setOf(
                VisitorModifier.RunAsLateAsPossible,
            ),
    ) {
    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        if (node.elementType == EOL_COMMENT) {
            visitEolComment(node, autoCorrect, emit)
        } else if (node.elementType == BLOCK_COMMENT) {
            visitBlockComment(node, autoCorrect, emit)
        }
    }

    private fun visitEolComment(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        val text =
            node
                .text
                .removePrefix("//")
                .trim()
        val parts = text.split(" ").filter { it.isNotBlank() }
        if (parts.isEmpty() || parts[0] != KTLINT_DISABLE) {
            return
        }

        val ruleIds = parts.drop(1).toSuppressAnnotationValues()
        emit(
            node.startOffset,
            "Directive 'ktlint-disable' in EOL comment is deprecated. Replace with @Suppress annotation",
            true,
        )
        if (autoCorrect) {
            removeEolCommentAndReplaceWithSuppressAnnotation(node, ruleIds)
        }
    }

    private fun visitBlockComment(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        val text =
            node
                .text
                .removePrefix("/*")
                .removeSuffix("*/")
                .trim()
        val parts = text.split(" ").filter { it.isNotBlank() }
        if (parts.isEmpty()) {
            return
        }

        if (parts[0] == KTLINT_DISABLE) {
            val ruleIds = parts.drop(1).toSuppressAnnotationValues()
            emit(
                node.startOffset,
                "Directive 'ktlint-disable' in block comment is deprecated. Replace with @Suppress annotation",
                true,
            )
            if (autoCorrect) {
                removeBlockDisableCommentAndAddSuppressAnnotation(node, ruleIds)
            }
        } else if (parts[0] == KTLINT_ENABLE) {
            emit(
                node.startOffset,
                "Directive 'ktlint-enable' in block comment is deprecated. Replace with @Suppress annotation",
                true,
            )
            if (autoCorrect) {
                removeBlockEnableComment(node)
            }
        }
    }

    private fun List<String>.toSuppressAnnotationValues(): List<String> =
        if (isEmpty()) {
            listOf("ktlint")
        } else {
            map { ruleId ->
                if (ruleId.contains(":")) {
                    // Already qualified rule id
                    "ktlint:${ruleId.removePrefix("experimental:").let { 
                        if (!it.contains(":")) {
                            "standard:$it"
                        } else {
                            it
                        }
                    }}"
                } else {
                    "ktlint:standard:$ruleId"
                }
            }
        }

    private fun removeEolCommentAndReplaceWithSuppressAnnotation(
        node: ASTNode,
        suppressAnnotationValues: List<String>,
    ) {
        val suppressAnnotation = suppressAnnotationValues.toSuppressAnnotationString()

        // Find the statement or declaration to annotate
        val parent = node.treeParent
        val target = findTargetForEolComment(node)

        if (target != null) {
            addSuppressAnnotation(target, suppressAnnotation)
        }

        // Remove the EOL comment and the preceding whitespace (if the whitespace only separates the code from comment)
        val prevLeaf = node.prevLeaf()
        if (prevLeaf != null && prevLeaf.elementType == WHITE_SPACE && !prevLeaf.textContains('\n')) {
            prevLeaf.treeParent.removeChild(prevLeaf)
        }
        node.treeParent.removeChild(node)
    }

    private fun findTargetForEolComment(node: ASTNode): ASTNode? {
        // Walk up to find the closest statement or declaration containing this EOL comment
        var current = node.treeParent
        while (current != null) {
            if (current.psi is KtDeclaration || current.psi is KtExpression) {
                // Don't go beyond file level
                if (current.treeParent?.elementType == FILE ||
                    current.treeParent?.psi is KtScript ||
                    (current.treeParent?.psi is KtDeclaration && current.psi is KtDeclaration)
                ) {
                    return current
                }
            }
            if (current.elementType == FILE) {
                return null
            }
            current = current.treeParent
        }
        return null
    }

    private fun removeBlockDisableCommentAndAddSuppressAnnotation(
        node: ASTNode,
        suppressAnnotationValues: List<String>,
    ) {
        val suppressAnnotation = suppressAnnotationValues.toSuppressAnnotationString()

        // Find the matching enable comment
        val enableComment = findMatchingEnableComment(node, suppressAnnotationValues)

        // Find the target to annotate - it's the next sibling construct after the disable comment
        val target = findTargetForBlockComment(node)

        if (target != null) {
            addSuppressAnnotation(target, suppressAnnotation)
        }

        // Remove the enable comment if found
        if (enableComment != null) {
            removeBlockEnableComment(enableComment)
        }

        // Remove the disable comment and surrounding whitespace
        removeBlockCommentAndSurroundingWhitespace(node)
    }

    private fun findMatchingEnableComment(
        disableNode: ASTNode,
        suppressAnnotationValues: List<String>,
    ): ASTNode? {
        val parent = disableNode.treeParent
        var sibling = disableNode.treeNext
        while (sibling != null) {
            if (sibling.elementType == BLOCK_COMMENT) {
                val text =
                    sibling
                        .text
                        .removePrefix("/*")
                        .removeSuffix("*/")
