                    val enableRuleIds = parts.drop(1).toSuppressAnnotationValues()
                    if (enableRuleIds == suppressAnnotationValues) {
                        return sibling
                    }
                }
            }
            sibling = sibling.treeNext
        }
        return null
    }

    private fun findTargetForBlockComment(node: ASTNode): ASTNode? {
        // The next code sibling after the block comment
        val nextSibling = node.nextCodeSibling()
        if (nextSibling != null && (nextSibling.psi is KtDeclaration || nextSibling.psi is KtExpression)) {
            return nextSibling
        }
        return null
    }

    private fun removeBlockEnableComment(node: ASTNode) {
