        val parent = node.treeParent
        parent.removeChild(node)

        // Clean up whitespace: if prev is whitespace with newline and next is also whitespace with newline,
        // remove one of them to avoid blank line
        if (prevLeaf != null && prevLeaf.elementType == WHITE_SPACE && prevLeaf.textContains('\n') &&
            nextLeaf != null && nextLeaf.elementType == WHITE_SPACE && nextLeaf.textContains('\n')
        ) {
            try {
                nextLeaf.treeParent?.removeChild(nextLeaf)
            } catch (_: Exception) {
                // Node may have already been removed
            }
        } else if (prevLeaf != null && prevLeaf.elementType == WHITE_SPACE && !prevLeaf.textContains('\n')) {
            // If the whitespace before comment is on the same line (no newline), remove it
            try {
                prevLeaf.treeParent?.removeChild(prevLeaf)
            } catch (_: Exception) {
                // Node may have already been removed
            }
        }
    }

    private fun addSuppressAnnotation(
        target: ASTNode,
        suppressAnnotation: String,
    ) {
        val psiElement = target.psi
        if (psiElement is KtAnnotated) {
            // Check if there's already a @Suppress annotation
            val existingSuppress = findExistingSuppressAnnotation(psiElement)
            if (existingSuppress != null) {
                mergeWithExistingSuppress(existingSuppress, suppressAnnotation)
                return
            }
        }

        // Insert the annotation before the target node
        val indent = getIndent(target)
        val annotationText = "@Suppress($suppressAnnotation)"

        val targetLeaf = target.firstChildNode ?: target
        if (targetLeaf is LeafPsiElement) {
            // Insert annotation + newline + indent before the target
            val annotationNode = LeafPsiElement(EOL_COMMENT, annotationText)
            // We need to insert as raw text because we can't easily create annotation nodes
            // Instead, we'll insert as text into the whitespace before
            val prevWhitespace = target.prevLeaf()
            if (prevWhitespace != null && prevWhitespace.elementType == WHITE_SPACE && prevWhitespace.textContains('\n')) {
                val newText = prevWhitespace.text + "$annotationText\n$indent"
                (prevWhitespace as LeafPsiElement).rawReplaceWithText(newText)
            } else {
                // No preceding whitespace with newline, insert before the target
                PsiWhiteSpaceImpl("$annotationText\n$indent").also { ws ->
                    (targetLeaf as LeafPsiElement).rawInsertBeforeMe(ws)
                }
            }
        }
    }

    private fun findExistingSuppressAnnotation(ktAnnotated: KtAnnotated): KtAnnotationEntry? =
        ktAnnotated
            .annotationEntries
            .firstOrNull { annotationEntry ->
                annotationEntry
                    .calleeExpression
                    ?.constructorReferenceExpression
                    ?.getReferencedName() in SUPPRESS_ANNOTATIONS
            }

    private fun mergeWithExistingSuppress(
        existingSuppress: KtAnnotationEntry,
        suppressAnnotation: String,
    ) {
        val existingValues =
            existingSuppress
                .valueArguments
                .mapNotNull { it.getArgumentExpression()?.text }
        val newValues = suppressAnnotation.split(", ").map { it.trim() }
        val allValues = (existingValues + newValues).distinct()

        val newAnnotationText = "@Suppress(${allValues.joinToString(", ")})"

        val node = existingSuppress.node
        // Replace the entire annotation entry
        val parent = node.treeParent
        val annotationLeaf = node.firstChildNode
        if (annotationLeaf is LeafPsiElement) {
            // Can't easily replace a complex annotation. Just replace text.
            val startOffset = node.startOffset
            val endOffset = node.startOffset + node.textLength
        }
    }

    private fun getIndent(node: ASTNode): String {
        val prevLeaf = node.prevLeaf()
        if (prevLeaf != null && prevLeaf.elementType == WHITE_SPACE && prevLeaf.textContains('\n')) {
            return prevLeaf.text.substringAfterLast('\n')
        }
        return ""
    }

    private fun List<String>.toSuppressAnnotationString(): String =
        joinToString(", ") { "\"$it\"" }

    private companion object {
        val SUPPRESS_ANNOTATIONS = setOf("Suppress", "SuppressWarnings")
        const val KTLINT_DISABLE = "ktlint-disable"
        const val KTLINT_ENABLE = "ktlint-enable"
    }
}

public val KTLINT_SUPPRESSION_RULE_ID: RuleId = KtlintSuppressionRule().ruleId
