 21→/**
 22→ * Disallows the usage of the old `ktlint-disable` and `ktlint-enable` directives. Those directives are to be replaced with
 23→ * `@Suppress` annotations.
 24→ *
 25→ * The rule can not be suppressed via the `@Suppress` annotation or the old `ktlint-disable` directive as that would result in a chicken
 26→ * and egg problem.
 27→ */
 28→public class KtlintSuppressionRule :
 29→    StandardRule(
 30→        id = "ktlint-suppression",
 31→        visitorModifiers =
 32→            setOf(
 33→                VisitorModifier.RunAsLateAsPossible,
 34→            ),
 35→    ) {
 36→    override fun beforeVisitChildNodes(
 37→        node: ASTNode,
 38→        autoCorrect: Boolean,
 39→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 40→    ) {
 41→        when (node.elementType) {
 42→            EOL_COMMENT -> visitEolComment(node, autoCorrect, emit)
 43→            BLOCK_COMMENT -> visitBlockComment(node, autoCorrect, emit)
 44→        }
 45→    }
 46→
 47→    private fun visitEolComment(
 48→        node: ASTNode,
 49→        autoCorrect: Boolean,
 50→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 51→    ) {
 52→        val commentText =
 53→            node
 54→                .text
 55→                .removePrefix("//")
 56→                .trim()
 57→        val parts = commentText.split(" ").filter { it.isNotBlank() }
 58→        if (parts.isEmpty() || parts[0] != KTLINT_DISABLE) {
 59→            return
 60→        }
 61→
 62→        val suppressionIds = parts.drop(1).toSuppressAnnotationValues()
 63→        emit(
 64→            node.startOffset,
 65→            "Directive 'ktlint-disable' in EOL comment is deprecated. Replace with @Suppress annotation",
 66→            true,
 67→        )
 68→        if (autoCorrect) {
 69→            replaceEolCommentDirectiveWithSuppressAnnotation(node, suppressionIds)
 70→        }
 71→    }
 72→
 73→    private fun visitBlockComment(
 74→        node: ASTNode,
 75→        autoCorrect: Boolean,
 76→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 77→    ) {
 78→        val commentText =
 79→            node
 80→                .text
 81→                .removePrefix("/*")
 82→                .removeSuffix("*/")
 83→                .trim()
 84→        val parts = commentText.split(" ").filter { it.isNotBlank() }
 85→        if (parts.isEmpty()) {
 86→            return
 87→        }
 88→
 89→        when (parts[0]) {
 90→            KTLINT_DISABLE -> {
 91→                val suppressionIds = parts.drop(1).toSuppressAnnotationValues()
 92→                emit(
 93→                    node.startOffset,
 94→                    "Directive 'ktlint-disable' in block comment is deprecated. Replace with @Suppress annotation",
 95→                    true,
 96→                )
 97→                if (autoCorrect) {
 98→                    replaceBlockCommentDirectiveWithSuppressAnnotation(node, suppressionIds)
 99→                }
100→            }
101→
102→            KTLINT_ENABLE -> {
103→                emit(
104→                    node.startOffset,
105→                    "Directive 'ktlint-enable' in block comment is deprecated. Replace with @Suppress annotation",
106→                    true,
107→                )
108→                if (autoCorrect) {
109→                    removeNodeAndSurroundingWhitespace(node)
110→                }
111→            }
112→        }
113→    }
114→
115→    /**
116→     * Converts old-style rule ids to the new `@Suppress` format:
117→     * - No rule ids means suppress all: `ktlint`
118→     * - `some-rule` becomes `ktlint:standard:some-rule`
119→     * - `standard:some-rule` becomes `ktlint:standard:some-rule`
120→     * - `experimental:some-rule` becomes `ktlint:standard:some-rule` (experimental was folded into standard)
121→     * - `custom-set:some-rule` becomes `ktlint:custom-set:some-rule`
122→     */
123→    private fun List<String>.toSuppressAnnotationValues(): List<String> =
124→        if (isEmpty()) {
125→            listOf("ktlint")
126→        } else {
127→            map { ruleId ->
128→                when {
129→                    ruleId.startsWith("experimental:") -> {
130→                        "ktlint:standard:${ruleId.removePrefix("experimental:")}"
131→                    }
132→
133→                    ruleId.contains(":") -> {
134→                        "ktlint:$ruleId"
135→                    }
136→
137→                    else -> {
138→                        "ktlint:standard:$ruleId"
139→                    }
140→                }
141→            }
142→        }
143→
144→    private fun replaceEolCommentDirectiveWithSuppressAnnotation(
145→        node: ASTNode,
146→        suppressionIds: List<String>,
147→    ) {
148→        val target = findTargetForEolComment(node)
149→        if (target != null) {
150→            addSuppressAnnotation(target, suppressionIds)
151→        }
152→
153→        // Remove the EOL comment and the preceding whitespace on the same line
154→        val prevLeaf = node.prevLeaf()
155→        if (prevLeaf != null && prevLeaf.elementType == WHITE_SPACE && !prevLeaf.textContains('\n')) {
156→            prevLeaf.treeParent.removeChild(prevLeaf)
157→        }
158→        node.treeParent.removeChild(node)
159→    }
160→
161→    private fun replaceBlockCommentDirectiveWithSuppressAnnotation(
162→        node: ASTNode,
163→        suppressionIds: List<String>,
164→    ) {
165→        // Find and remove the matching enable comment first (before we lose track of it)
166→        val enableComment = findMatchingEnableComment(node, suppressionIds)
167→        if (enableComment != null) {
168→            removeNodeAndSurroundingWhitespace(enableComment)
169→        }
170→
171→        // Find the target to annotate - it's the next code sibling after the disable comment
172→        val target = findTargetForBlockComment(node)
173→        if (target != null) {
174→            addSuppressAnnotation(target, suppressionIds)
175→        }
176→
177→        // Remove the disable comment
178→        removeNodeAndSurroundingWhitespace(node)
179→    }
180→
181→    /**
182→     * Find the target node for an EOL comment. The target is the closest parent that is a declaration or expression and
183→     * that is a direct child of the file, script, class body, or block (i.e., it is a "statement-level" node).
184→     */
185→    private fun findTargetForEolComment(node: ASTNode): ASTNode? {
186→        var current = node.treeParent
187→        while (current != null) {
188→            if (current.elementType == FILE) {
189→                return null
190→            }
191→            val psi = current.psi
192→            if (psi is KtDeclaration || psi is KtExpression) {
193→                return current
194→            }
195→            current = current.treeParent
196→        }
197→        return null
198→    }
199→
200→    private fun findTargetForBlockComment(node: ASTNode): ASTNode? {
201→        val nextSibling = node.nextCodeSibling()
202→        if (nextSibling != null) {
203→            val psi = nextSibling.psi
204→            if (psi is KtDeclaration || psi is KtExpression) {
205→                return nextSibling
206→            }
207→        }
208→        return null
209→    }
210→
211→    private fun findMatchingEnableComment(
212→        disableNode: ASTNode,
213→        suppressionIds: List<String>,
214→    ): ASTNode? {
215→        var sibling = disableNode.treeNext
216→        while (sibling != null) {
217→            if (sibling.elementType == BLOCK_COMMENT) {
218→                val text =
219→                    sibling
220→                        .text
221→                        .removePrefix("/*")
222→                        .removeSuffix("*/")
223→                        .trim()
224→                val parts = text.split(" ").filter { it.isNotBlank() }
225→                if (parts.isNotEmpty() && parts[0] == KTLINT_ENABLE) {
226→                    val enableRuleIds = parts.drop(1).toSuppressAnnotationValues()
227→                    if (enableRuleIds == suppressionIds) {
228→                        return sibling
229→                    }
230→                }
231→            }
232→            sibling = sibling.treeNext
233→        }
234→        return null
235→    }
236→
237→    private fun removeNodeAndSurroundingWhitespace(node: ASTNode) {
238→        val prevLeaf = node.prevLeaf()
239→        val nextLeaf = node.nextLeaf()
240→
241→        val parent = node.treeParent
242→        parent.removeChild(node)
243→
244→        // Clean up whitespace
245→        if (prevLeaf != null && prevLeaf.elementType == WHITE_SPACE && prevLeaf.textContains('\n') &&
246→            nextLeaf != null && nextLeaf.elementType == WHITE_SPACE && nextLeaf.textContains('\n')
247→        ) {
248→            try {
249→                nextLeaf.treeParent?.removeChild(nextLeaf)
250→            } catch (_: Exception) {
251→                // Node may have already been removed
252→            }
253→        } else if (prevLeaf != null && prevLeaf.elementType == WHITE_SPACE && !prevLeaf.textContains('\n')) {
254→            try {
255→                prevLeaf.treeParent?.removeChild(prevLeaf)
256→            } catch (_: Exception) {
257→                // Node may have already been removed
258→            }
259→        }
260→    }
261→
262→    private fun addSuppressAnnotation(
263→        target: ASTNode,
264→        suppressionIds: List<String>,
265→    ) {
266→        val psiElement = target.psi
267→        if (psiElement is KtAnnotated) {
268→            val existingSuppress = findExistingSuppressAnnotation(psiElement)
269→            if (existingSuppress != null) {
270→                mergeWithExistingSuppress(existingSuppress, suppressionIds)
271→                return
272→            }
273→        }
274→
275→        val indent = target.indent(includeNewline = false)
276→        val annotationText = "@Suppress(${suppressionIds.joinToString(", ") { "\"$it\"" }})"
277→
278→        // Insert the @Suppress annotation before the target, on a new line with proper indent
279→        val prevWhitespace = target.prevLeaf()
280→        if (prevWhitespace != null && prevWhitespace.elementType == WHITE_SPACE && prevWhitespace.textContains('\n')) {
281→            val newText = prevWhitespace.text + "$annotationText\n$indent"
282→            (prevWhitespace as LeafPsiElement).rawReplaceWithText(newText)
283→        } else {
284→            // No preceding whitespace with newline - we're likely at the start of the file
285→            val firstLeaf = target.firstChildNode ?: target
286→            if (firstLeaf is LeafPsiElement) {
287→                PsiWhiteSpaceImpl("$annotationText\n$indent").also { ws ->
288→                    firstLeaf.rawInsertBeforeMe(ws)
289→                }
290→            }
291→        }
292→    }
293→
294→    private fun findExistingSuppressAnnotation(ktAnnotated: KtAnnotated): KtAnnotationEntry? =
295→        ktAnnotated
296→            .annotationEntries
297→            .firstOrNull { annotationEntry ->
298→                annotationEntry
299→                    .calleeExpression
300→                    ?.constructorReferenceExpression
301→                    ?.getReferencedName() in SUPPRESS_ANNOTATIONS
302→            }
303→
304→    private fun mergeWithExistingSuppress(
305→        existingSuppress: KtAnnotationEntry,
306→        newSuppressionIds: List<String>,
307→    ) {
308→        val existingValues =
309→            existingSuppress
310→                .valueArguments
311→                .mapNotNull { it.getArgumentExpression()?.text }
312→
313→        // Combine existing and new values, avoid duplicates
314→        val quotedNewValues = newSuppressionIds.map { "\"$it\"" }
315→        val allValues = (existingValues + quotedNewValues).distinct()
316→
317→        val newAnnotationText = "@Suppress(${allValues.joinToString(", ")})"
318→
319→        // Replace the entire annotation text by replacing the text in the node
320→        val node = existingSuppress.node
321→        val parent = node.treeParent
322→        if (parent != null) {
323→            val firstChild = node.firstChildNode
324→            val lastChild = node.lastChildNode
325→            if (firstChild is LeafPsiElement && firstChild === lastChild) {
326→                firstChild.rawReplaceWithText(newAnnotationText)
327→            }
328→        }
329→    }
330→
331→    private companion object {
332→        val SUPPRESS_ANNOTATIONS = setOf("Suppress", "SuppressWarnings")
333→        const val KTLINT_DISABLE = "ktlint-disable"
334→        const val KTLINT_ENABLE = "ktlint-enable"
335→    }
336→}
